import{_ as h,C as o,o as u,c as m,ag as i,E as s,w as a,a as t,j as n}from"./chunks/framework.eQLvDOR_.js";const v=JSON.parse('{"title":"How Claude remembers your project","description":"","frontmatter":{"title":"How Claude remembers your project","source":"unknown","clipped_at":"2026-04-04","category":"[AI_IDE_And_CLI]","tags":["ai-ide-and-cli"],"status":"distilled","compiled":true},"headers":[],"relativePath":"library/AI_IDE_And_CLI/AI_IDE_And_CLI - How Claude remembers your project.md","filePath":"library/AI_IDE_And_CLI/AI_IDE_And_CLI - How Claude remembers your project.md","lastUpdated":null}'),g={name:"library/AI_IDE_And_CLI/AI_IDE_And_CLI - How Claude remembers your project.md"};function f(y,e,k,b,C,E){const r=o("Tip"),c=o("Warning"),l=o("Note"),d=o("Step"),p=o("Steps");return u(),m("div",null,[e[7]||(e[7]=i('<blockquote><h2 id="documentation-index" tabindex="-1">Documentation Index <a class="header-anchor" href="#documentation-index" aria-label="Permalink to &quot;Documentation Index&quot;">​</a></h2><p>Fetch the complete documentation index at: <a href="https://code.claude.com/docs/llms.txt" target="_blank" rel="noreferrer">https://code.claude.com/docs/llms.txt</a> Use this file to discover all available pages before exploring further.</p></blockquote><h1 id="how-claude-remembers-your-project" tabindex="-1">How Claude remembers your project <a class="header-anchor" href="#how-claude-remembers-your-project" aria-label="Permalink to &quot;How Claude remembers your project&quot;">​</a></h1><blockquote><p>Give Claude persistent instructions with CLAUDE.md files, and let Claude accumulate learnings automatically with auto memory.</p></blockquote><p>Each Claude Code session begins with a fresh context window. Two mechanisms carry knowledge across sessions:</p><ul><li><strong>CLAUDE.md files</strong>: instructions you write to give Claude persistent context</li><li><strong>Auto memory</strong>: notes Claude writes itself based on your corrections and preferences</li></ul><p>This page covers how to:</p><ul><li><a href="#claude-md-files">Write and organize CLAUDE.md files</a></li><li><a href="#organize-rules-with-claude/rules/">Scope rules to specific file types</a> with <code>.claude/rules/</code></li><li><a href="#auto-memory">Configure auto memory</a> so Claude takes notes automatically</li><li><a href="#troubleshoot-memory-issues">Troubleshoot</a> when instructions aren&#39;t being followed</li></ul><h2 id="claude-md-vs-auto-memory" tabindex="-1">CLAUDE.md vs auto memory <a class="header-anchor" href="#claude-md-vs-auto-memory" aria-label="Permalink to &quot;CLAUDE.md vs auto memory&quot;">​</a></h2><p>Claude Code has two complementary memory systems. Both are loaded at the start of every conversation. Claude treats them as context, not enforced configuration. The more specific and concise your instructions, the more consistently Claude follows them.</p><table tabindex="0"><thead><tr><th style="text-align:left;"></th><th style="text-align:left;">CLAUDE.md files</th><th style="text-align:left;">Auto memory</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Who writes it</strong></td><td style="text-align:left;">You</td><td style="text-align:left;">Claude</td></tr><tr><td style="text-align:left;"><strong>What it contains</strong></td><td style="text-align:left;">Instructions and rules</td><td style="text-align:left;">Learnings and patterns</td></tr><tr><td style="text-align:left;"><strong>Scope</strong></td><td style="text-align:left;">Project, user, or org</td><td style="text-align:left;">Per working tree</td></tr><tr><td style="text-align:left;"><strong>Loaded into</strong></td><td style="text-align:left;">Every session</td><td style="text-align:left;">Every session (first 200 lines or 25KB)</td></tr><tr><td style="text-align:left;"><strong>Use for</strong></td><td style="text-align:left;">Coding standards, workflows, project architecture</td><td style="text-align:left;">Build commands, debugging insights, preferences Claude discovers</td></tr></tbody></table><p>Use CLAUDE.md files when you want to guide Claude&#39;s behavior. Auto memory lets Claude learn from your corrections without manual effort.</p><p>Subagents can also maintain their own auto memory. See <a href="/s/webclips/en/sub-agents.html#enable-persistent-memory">subagent configuration</a> for details.</p><h2 id="claude-md-files" tabindex="-1">CLAUDE.md files <a class="header-anchor" href="#claude-md-files" aria-label="Permalink to &quot;CLAUDE.md files&quot;">​</a></h2><p>CLAUDE.md files are markdown files that give Claude persistent instructions for a project, your personal workflow, or your entire organization. You write these files in plain text; Claude reads them at the start of every session.</p><h3 id="choose-where-to-put-claude-md-files" tabindex="-1">Choose where to put CLAUDE.md files <a class="header-anchor" href="#choose-where-to-put-claude-md-files" aria-label="Permalink to &quot;Choose where to put CLAUDE.md files&quot;">​</a></h3><p>CLAUDE.md files can live in several locations, each with a different scope. More specific locations take precedence over broader ones.</p><table tabindex="0"><thead><tr><th>Scope</th><th>Location</th><th>Purpose</th><th>Use case examples</th><th>Shared with</th></tr></thead><tbody><tr><td><strong>Managed policy</strong></td><td>• macOS: <code>/Library/Application Support/ClaudeCode/CLAUDE.md</code><br>• Linux and WSL: <code>/etc/claude-code/CLAUDE.md</code><br>• Windows: <code>C:\\Program Files\\ClaudeCode\\CLAUDE.md</code></td><td>Organization-wide instructions managed by IT/DevOps</td><td>Company coding standards, security policies, compliance requirements</td><td>All users in organization</td></tr><tr><td><strong>Project instructions</strong></td><td><code>./CLAUDE.md</code> or <code>./.claude/CLAUDE.md</code></td><td>Team-shared instructions for the project</td><td>Project architecture, coding standards, common workflows</td><td>Team members via source control</td></tr><tr><td><strong>User instructions</strong></td><td><code>~/.claude/CLAUDE.md</code></td><td>Personal preferences for all projects</td><td>Code styling preferences, personal tooling shortcuts</td><td>Just you (all projects)</td></tr></tbody></table><p>CLAUDE.md files in the directory hierarchy above the working directory are loaded in full at launch. CLAUDE.md files in subdirectories load on demand when Claude reads files in those directories. See <a href="#how-claude-md-files-load">How CLAUDE.md files load</a> for the full resolution order.</p><p>For large projects, you can break instructions into topic-specific files using <a href="#organize-rules-with-claude/rules/">project rules</a>. Rules let you scope instructions to specific file types or subdirectories.</p><h3 id="set-up-a-project-claude-md" tabindex="-1">Set up a project CLAUDE.md <a class="header-anchor" href="#set-up-a-project-claude-md" aria-label="Permalink to &quot;Set up a project CLAUDE.md&quot;">​</a></h3><p>A project CLAUDE.md can be stored in either <code>./CLAUDE.md</code> or <code>./.claude/CLAUDE.md</code>. Create this file and add instructions that apply to anyone working on the project: build and test commands, coding standards, architectural decisions, naming conventions, and common workflows. These instructions are shared with your team through version control, so focus on project-level standards rather than personal preferences.</p>',21)),s(r,null,{default:a(()=>[...e[0]||(e[0]=[t(" Run `/init` to generate a starting CLAUDE.md automatically. Claude analyzes your codebase and creates a file with build commands, test instructions, and project conventions it discovers. If a CLAUDE.md already exists, `/init` suggests improvements rather than overwriting it. Refine from there with instructions Claude wouldn't discover on its own. ",-1),n("p",null,[t("Set "),n("code",null,"CLAUDE_CODE_NEW_INIT=true"),t(" to enable an interactive multi-phase flow. "),n("code",null,"/init"),t(" asks which artifacts to set up: CLAUDE.md files, skills, and hooks. It then explores your codebase with a subagent, fills in gaps via follow-up questions, and presents a reviewable proposal before writing any files.")],-1)])]),_:1}),e[8]||(e[8]=i(`<h3 id="write-effective-instructions" tabindex="-1">Write effective instructions <a class="header-anchor" href="#write-effective-instructions" aria-label="Permalink to &quot;Write effective instructions&quot;">​</a></h3><p>CLAUDE.md files are loaded into the context window at the start of every session, consuming tokens alongside your conversation. The <a href="/s/webclips/en/context-window.html">context window visualization</a> shows where CLAUDE.md loads relative to the rest of the startup context. Because they&#39;re context rather than enforced configuration, how you write instructions affects how reliably Claude follows them. Specific, concise, well-structured instructions work best.</p><p><strong>Size</strong>: target under 200 lines per CLAUDE.md file. Longer files consume more context and reduce adherence. If your instructions are growing large, split them using <a href="#import-additional-files">imports</a> or <a href="#organize-rules-with-claude/rules/"><code>.claude/rules/</code></a> files.</p><p><strong>Structure</strong>: use markdown headers and bullets to group related instructions. Claude scans structure the same way readers do: organized sections are easier to follow than dense paragraphs.</p><p><strong>Specificity</strong>: write instructions that are concrete enough to verify. For example:</p><ul><li>&quot;Use 2-space indentation&quot; instead of &quot;Format code properly&quot;</li><li>&quot;Run <code>npm test</code> before committing&quot; instead of &quot;Test your changes&quot;</li><li>&quot;API handlers live in <code>src/api/handlers/</code>&quot; instead of &quot;Keep files organized&quot;</li></ul><p><strong>Consistency</strong>: if two rules contradict each other, Claude may pick one arbitrarily. Review your CLAUDE.md files, nested CLAUDE.md files in subdirectories, and <a href="#organize-rules-with-claude/rules/"><code>.claude/rules/</code></a> periodically to remove outdated or conflicting instructions. In monorepos, use <a href="#exclude-specific-claude-md-files"><code>claudeMdExcludes</code></a> to skip CLAUDE.md files from other teams that aren&#39;t relevant to your work.</p><h3 id="import-additional-files" tabindex="-1">Import additional files <a class="header-anchor" href="#import-additional-files" aria-label="Permalink to &quot;Import additional files&quot;">​</a></h3><p>CLAUDE.md files can import additional files using <code>@path/to/import</code> syntax. Imported files are expanded and loaded into context at launch alongside the CLAUDE.md that references them.</p><p>Both relative and absolute paths are allowed. Relative paths resolve relative to the file containing the import, not the working directory. Imported files can recursively import other files, with a maximum depth of five hops.</p><p>To pull in a README, package.json, and a workflow guide, reference them with <code>@</code> syntax anywhere in your CLAUDE.md:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>See @README for project overview and @package.json for available npm commands for this project.</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Additional Instructions</span></span>
<span class="line"><span>- git workflow @docs/git-instructions.md</span></span></code></pre></div><p>For personal preferences you don&#39;t want to check in, import a file from your home directory. The import goes in the shared CLAUDE.md, but the file it points to stays on your machine:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># Individual Preferences</span></span>
<span class="line"><span>- @~/.claude/my-project-instructions.md</span></span></code></pre></div>`,14)),s(c,null,{default:a(()=>[...e[1]||(e[1]=[t(" The first time Claude Code encounters external imports in a project, it shows an approval dialog listing the files. If you decline, the imports stay disabled and the dialog does not appear again. ",-1)])]),_:1}),e[9]||(e[9]=i('<p>For a more structured approach to organizing instructions, see <a href="#organize-rules-with-claude/rules/"><code>.claude/rules/</code></a>.</p><h3 id="agents-md" tabindex="-1">AGENTS.md <a class="header-anchor" href="#agents-md" aria-label="Permalink to &quot;AGENTS.md&quot;">​</a></h3><p>Claude Code reads <code>CLAUDE.md</code>, not <code>AGENTS.md</code>. If your repository already uses <code>AGENTS.md</code> for other coding agents, create a <code>CLAUDE.md</code> that imports it so both tools read the same instructions without duplicating them. You can also add Claude-specific instructions below the import. Claude loads the imported file at session start, then appends the rest:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">@AGENTS.md</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Claude Code</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Use plan mode for changes under </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">`src/billing/`</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span></span></code></pre></div><h3 id="how-claude-md-files-load" tabindex="-1">How CLAUDE.md files load <a class="header-anchor" href="#how-claude-md-files-load" aria-label="Permalink to &quot;How CLAUDE.md files load&quot;">​</a></h3><p>Claude Code reads CLAUDE.md files by walking up the directory tree from your current working directory, checking each directory along the way. This means if you run Claude Code in <code>foo/bar/</code>, it loads instructions from both <code>foo/bar/CLAUDE.md</code> and <code>foo/CLAUDE.md</code>.</p><p>Claude also discovers CLAUDE.md files in subdirectories under your current working directory. Instead of loading them at launch, they are included when Claude reads files in those subdirectories.</p><p>If you work in a large monorepo where other teams&#39; CLAUDE.md files get picked up, use <a href="#exclude-specific-claude-md-files"><code>claudeMdExcludes</code></a> to skip them.</p><p>Block-level HTML comments (<code>&lt;!-- maintainer notes --&gt;</code>) in CLAUDE.md files are stripped before the content is injected into Claude&#39;s context. Use them to leave notes for human maintainers without spending context tokens on them. Comments inside code blocks are preserved. When you open a CLAUDE.md file directly with the Read tool, comments remain visible.</p><h4 id="load-from-additional-directories" tabindex="-1">Load from additional directories <a class="header-anchor" href="#load-from-additional-directories" aria-label="Permalink to &quot;Load from additional directories&quot;">​</a></h4><p>The <code>--add-dir</code> flag gives Claude access to additional directories outside your main working directory. By default, CLAUDE.md files from these directories are not loaded.</p><p>To also load CLAUDE.md files from additional directories, including <code>CLAUDE.md</code>, <code>.claude/CLAUDE.md</code>, and <code>.claude/rules/*.md</code>, set the <code>CLAUDE_CODE_ADDITIONAL_DIRECTORIES_CLAUDE_MD</code> environment variable:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">CLAUDE_CODE_ADDITIONAL_DIRECTORIES_CLAUDE_MD</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">1</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --add-dir</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ../shared-config</span></span></code></pre></div><h3 id="organize-rules-with-claude-rules" tabindex="-1">Organize rules with <code>.claude/rules/</code> <a class="header-anchor" href="#organize-rules-with-claude-rules" aria-label="Permalink to &quot;Organize rules with `.claude/rules/`&quot;">​</a></h3><p>For larger projects, you can organize instructions into multiple files using the <code>.claude/rules/</code> directory. This keeps instructions modular and easier for teams to maintain. Rules can also be <a href="#path-specific-rules">scoped to specific file paths</a>, so they only load into context when Claude works with matching files, reducing noise and saving context space.</p>',15)),s(l,null,{default:a(()=>[...e[2]||(e[2]=[t(" Rules load into context every session or when matching files are opened. For task-specific instructions that don't need to be in context all the time, use [skills](/en/skills) instead, which only load when you invoke them or when Claude determines they're relevant to your prompt. ",-1)])]),_:1}),e[10]||(e[10]=i(`<h4 id="set-up-rules" tabindex="-1">Set up rules <a class="header-anchor" href="#set-up-rules" aria-label="Permalink to &quot;Set up rules&quot;">​</a></h4><p>Place markdown files in your project&#39;s <code>.claude/rules/</code> directory. Each file should cover one topic, with a descriptive filename like <code>testing.md</code> or <code>api-design.md</code>. All <code>.md</code> files are discovered recursively, so you can organize rules into subdirectories like <code>frontend/</code> or <code>backend/</code>:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>your-project/</span></span>
<span class="line"><span>├── .claude/</span></span>
<span class="line"><span>│   ├── CLAUDE.md           # Main project instructions</span></span>
<span class="line"><span>│   └── rules/</span></span>
<span class="line"><span>│       ├── code-style.md   # Code style guidelines</span></span>
<span class="line"><span>│       ├── testing.md      # Testing conventions</span></span>
<span class="line"><span>│       └── security.md     # Security requirements</span></span></code></pre></div><p>Rules without <a href="#path-specific-rules"><code>paths</code> frontmatter</a> are loaded at launch with the same priority as <code>.claude/CLAUDE.md</code>.</p><h4 id="path-specific-rules" tabindex="-1">Path-specific rules <a class="header-anchor" href="#path-specific-rules" aria-label="Permalink to &quot;Path-specific rules&quot;">​</a></h4><p>Rules can be scoped to specific files using YAML frontmatter with the <code>paths</code> field. These conditional rules only apply when Claude is working with files matching the specified patterns.</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">---</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">paths</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;src/api/**/*.ts&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">---</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;"># API Development Rules</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> All API endpoints must include input validation</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Use the standard error response format</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Include OpenAPI documentation comments</span></span></code></pre></div><p>Rules without a <code>paths</code> field are loaded unconditionally and apply to all files. Path-scoped rules trigger when Claude reads files matching the pattern, not on every tool use.</p><p>Use glob patterns in the <code>paths</code> field to match files by extension, directory, or any combination:</p><table tabindex="0"><thead><tr><th>Pattern</th><th>Matches</th></tr></thead><tbody><tr><td><code>**/*.ts</code></td><td>All TypeScript files in any directory</td></tr><tr><td><code>src/**/*</code></td><td>All files under <code>src/</code> directory</td></tr><tr><td><code>*.md</code></td><td>Markdown files in the project root</td></tr><tr><td><code>src/components/*.tsx</code></td><td>React components in a specific directory</td></tr></tbody></table><p>You can specify multiple patterns and use brace expansion to match multiple extensions in one pattern:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">---</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">paths</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;src/**/*.{ts,tsx}&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;lib/**/*.ts&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;tests/**/*.test.ts&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">---</span></span></code></pre></div><h4 id="share-rules-across-projects-with-symlinks" tabindex="-1">Share rules across projects with symlinks <a class="header-anchor" href="#share-rules-across-projects-with-symlinks" aria-label="Permalink to &quot;Share rules across projects with symlinks&quot;">​</a></h4><p>The <code>.claude/rules/</code> directory supports symlinks, so you can maintain a shared set of rules and link them into multiple projects. Symlinks are resolved and loaded normally, and circular symlinks are detected and handled gracefully.</p><p>This example links both a shared directory and an individual file:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ln</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/shared-claude-rules</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .claude/rules/shared</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ln</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/company-standards/security.md</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .claude/rules/security.md</span></span></code></pre></div><h4 id="user-level-rules" tabindex="-1">User-level rules <a class="header-anchor" href="#user-level-rules" aria-label="Permalink to &quot;User-level rules&quot;">​</a></h4><p>Personal rules in <code>~/.claude/rules/</code> apply to every project on your machine. Use them for preferences that aren&#39;t project-specific:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.claude/rules/</span></span>
<span class="line"><span>├── preferences.md    # Your personal coding preferences</span></span>
<span class="line"><span>└── workflows.md      # Your preferred workflows</span></span></code></pre></div><p>User-level rules are loaded before project rules, giving project rules higher priority.</p><h3 id="manage-claude-md-for-large-teams" tabindex="-1">Manage CLAUDE.md for large teams <a class="header-anchor" href="#manage-claude-md-for-large-teams" aria-label="Permalink to &quot;Manage CLAUDE.md for large teams&quot;">​</a></h3><p>For organizations deploying Claude Code across teams, you can centralize instructions and control which CLAUDE.md files are loaded.</p><h4 id="deploy-organization-wide-claude-md" tabindex="-1">Deploy organization-wide CLAUDE.md <a class="header-anchor" href="#deploy-organization-wide-claude-md" aria-label="Permalink to &quot;Deploy organization-wide CLAUDE.md&quot;">​</a></h4><p>Organizations can deploy a centrally managed CLAUDE.md that applies to all users on a machine. This file cannot be excluded by individual settings.</p>`,24)),s(p,null,{default:a(()=>[s(d,{title:"Create the file at the managed policy location"},{default:a(()=>[...e[3]||(e[3]=[t(" * macOS: `/Library/Application Support/ClaudeCode/CLAUDE.md` * Linux and WSL: `/etc/claude-code/CLAUDE.md` * Windows: `C:\\Program Files\\ClaudeCode\\CLAUDE.md` ",-1)])]),_:1}),s(d,{title:"Deploy with your configuration management system"},{default:a(()=>[...e[4]||(e[4]=[t(" Use MDM, Group Policy, Ansible, or similar tools to distribute the file across developer machines. See [managed settings](/en/permissions#managed-settings) for other organization-wide configuration options. ",-1)])]),_:1})]),_:1}),e[11]||(e[11]=i(`<p>A managed CLAUDE.md and <a href="/s/webclips/en/settings.html#settings-files">managed settings</a> serve different purposes. Use settings for technical enforcement and CLAUDE.md for behavioral guidance:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Concern</th><th style="text-align:left;">Configure in</th></tr></thead><tbody><tr><td style="text-align:left;">Block specific tools, commands, or file paths</td><td style="text-align:left;">Managed settings: <code>permissions.deny</code></td></tr><tr><td style="text-align:left;">Enforce sandbox isolation</td><td style="text-align:left;">Managed settings: <code>sandbox.enabled</code></td></tr><tr><td style="text-align:left;">Environment variables and API provider routing</td><td style="text-align:left;">Managed settings: <code>env</code></td></tr><tr><td style="text-align:left;">Authentication method and organization lock</td><td style="text-align:left;">Managed settings: <code>forceLoginMethod</code>, <code>forceLoginOrgUUID</code></td></tr><tr><td style="text-align:left;">Code style and quality guidelines</td><td style="text-align:left;">Managed CLAUDE.md</td></tr><tr><td style="text-align:left;">Data handling and compliance reminders</td><td style="text-align:left;">Managed CLAUDE.md</td></tr><tr><td style="text-align:left;">Behavioral instructions for Claude</td><td style="text-align:left;">Managed CLAUDE.md</td></tr></tbody></table><p>Settings rules are enforced by the client regardless of what Claude decides to do. CLAUDE.md instructions shape Claude&#39;s behavior but are not a hard enforcement layer.</p><h4 id="exclude-specific-claude-md-files" tabindex="-1">Exclude specific CLAUDE.md files <a class="header-anchor" href="#exclude-specific-claude-md-files" aria-label="Permalink to &quot;Exclude specific CLAUDE.md files&quot;">​</a></h4><p>In large monorepos, ancestor CLAUDE.md files may contain instructions that aren&#39;t relevant to your work. The <code>claudeMdExcludes</code> setting lets you skip specific files by path or glob pattern.</p><p>This example excludes a top-level CLAUDE.md and a rules directory from a parent folder. Add it to <code>.claude/settings.local.json</code> so the exclusion stays local to your machine:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;claudeMdExcludes&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;**/monorepo/CLAUDE.md&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;/home/user/monorepo/other-team/.claude/rules/**&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  ]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Patterns are matched against absolute file paths using glob syntax. You can configure <code>claudeMdExcludes</code> at any <a href="/s/webclips/en/settings.html#settings-files">settings layer</a>: user, project, local, or managed policy. Arrays merge across layers.</p><p>Managed policy CLAUDE.md files cannot be excluded. This ensures organization-wide instructions always apply regardless of individual settings.</p><h2 id="auto-memory" tabindex="-1">Auto memory <a class="header-anchor" href="#auto-memory" aria-label="Permalink to &quot;Auto memory&quot;">​</a></h2><p>Auto memory lets Claude accumulate knowledge across sessions without you writing anything. Claude saves notes for itself as it works: build commands, debugging insights, architecture notes, code style preferences, and workflow habits. Claude doesn&#39;t save something every session. It decides what&#39;s worth remembering based on whether the information would be useful in a future conversation.</p>`,11)),s(l,null,{default:a(()=>[...e[5]||(e[5]=[t(" Auto memory requires Claude Code v2.1.59 or later. Check your version with `claude --version`. ",-1)])]),_:1}),e[12]||(e[12]=i(`<h3 id="enable-or-disable-auto-memory" tabindex="-1">Enable or disable auto memory <a class="header-anchor" href="#enable-or-disable-auto-memory" aria-label="Permalink to &quot;Enable or disable auto memory&quot;">​</a></h3><p>Auto memory is on by default. To toggle it, open <code>/memory</code> in a session and use the auto memory toggle, or set <code>autoMemoryEnabled</code> in your project settings:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;autoMemoryEnabled&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>To disable auto memory via environment variable, set <code>CLAUDE_CODE_DISABLE_AUTO_MEMORY=1</code>.</p><h3 id="storage-location" tabindex="-1">Storage location <a class="header-anchor" href="#storage-location" aria-label="Permalink to &quot;Storage location&quot;">​</a></h3><p>Each project gets its own memory directory at <code>~/.claude/projects/&lt;project&gt;/memory/</code>. The <code>&lt;project&gt;</code> path is derived from the git repository, so all worktrees and subdirectories within the same repo share one auto memory directory. Outside a git repo, the project root is used instead.</p><p>To store auto memory in a different location, set <code>autoMemoryDirectory</code> in your user or local settings:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;autoMemoryDirectory&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;~/my-custom-memory-dir&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>This setting is accepted from policy, local, and user settings. It is not accepted from project settings (<code>.claude/settings.json</code>) to prevent a shared project from redirecting auto memory writes to sensitive locations.</p><p>The directory contains a <code>MEMORY.md</code> entrypoint and optional topic files:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.claude/projects/&lt;project&gt;/memory/</span></span>
<span class="line"><span>├── MEMORY.md          # Concise index, loaded into every session</span></span>
<span class="line"><span>├── debugging.md       # Detailed notes on debugging patterns</span></span>
<span class="line"><span>├── api-conventions.md # API design decisions</span></span>
<span class="line"><span>└── ...                # Any other topic files Claude creates</span></span></code></pre></div><p><code>MEMORY.md</code> acts as an index of the memory directory. Claude reads and writes files in this directory throughout your session, using <code>MEMORY.md</code> to keep track of what&#39;s stored where.</p><p>Auto memory is machine-local. All worktrees and subdirectories within the same git repository share one auto memory directory. Files are not shared across machines or cloud environments.</p><h3 id="how-it-works" tabindex="-1">How it works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works&quot;">​</a></h3><p>The first 200 lines of <code>MEMORY.md</code>, or the first 25KB, whichever comes first, are loaded at the start of every conversation. Content beyond that threshold is not loaded at session start. Claude keeps <code>MEMORY.md</code> concise by moving detailed notes into separate topic files.</p><p>This limit applies only to <code>MEMORY.md</code>. CLAUDE.md files are loaded in full regardless of length, though shorter files produce better adherence.</p><p>Topic files like <code>debugging.md</code> or <code>patterns.md</code> are not loaded at startup. Claude reads them on demand using its standard file tools when it needs the information.</p><p>Claude reads and writes memory files during your session. When you see &quot;Writing memory&quot; or &quot;Recalled memory&quot; in the Claude Code interface, Claude is actively updating or reading from <code>~/.claude/projects/&lt;project&gt;/memory/</code>.</p><h3 id="audit-and-edit-your-memory" tabindex="-1">Audit and edit your memory <a class="header-anchor" href="#audit-and-edit-your-memory" aria-label="Permalink to &quot;Audit and edit your memory&quot;">​</a></h3><p>Auto memory files are plain markdown you can edit or delete at any time. Run <a href="#view-and-edit-with-memory"><code>/memory</code></a> to browse and open memory files from within a session.</p><h2 id="view-and-edit-with-memory" tabindex="-1">View and edit with <code>/memory</code> <a class="header-anchor" href="#view-and-edit-with-memory" aria-label="Permalink to &quot;View and edit with \`/memory\`&quot;">​</a></h2><p>The <code>/memory</code> command lists all CLAUDE.md and rules files loaded in your current session, lets you toggle auto memory on or off, and provides a link to open the auto memory folder. Select any file to open it in your editor.</p><p>When you ask Claude to remember something, like &quot;always use pnpm, not npm&quot; or &quot;remember that the API tests require a local Redis instance,&quot; Claude saves it to auto memory. To add instructions to CLAUDE.md instead, ask Claude directly, like &quot;add this to CLAUDE.md,&quot; or edit the file yourself via <code>/memory</code>.</p><h2 id="troubleshoot-memory-issues" tabindex="-1">Troubleshoot memory issues <a class="header-anchor" href="#troubleshoot-memory-issues" aria-label="Permalink to &quot;Troubleshoot memory issues&quot;">​</a></h2><p>These are the most common issues with CLAUDE.md and auto memory, along with steps to debug them.</p><h3 id="claude-isn-t-following-my-claude-md" tabindex="-1">Claude isn&#39;t following my CLAUDE.md <a class="header-anchor" href="#claude-isn-t-following-my-claude-md" aria-label="Permalink to &quot;Claude isn&#39;t following my CLAUDE.md&quot;">​</a></h3><p>CLAUDE.md content is delivered as a user message after the system prompt, not as part of the system prompt itself. Claude reads it and tries to follow it, but there&#39;s no guarantee of strict compliance, especially for vague or conflicting instructions.</p><p>To debug:</p><ul><li>Run <code>/memory</code> to verify your CLAUDE.md files are being loaded. If a file isn&#39;t listed, Claude can&#39;t see it.</li><li>Check that the relevant CLAUDE.md is in a location that gets loaded for your session (see <a href="#choose-where-to-put-claude-md-files">Choose where to put CLAUDE.md files</a>).</li><li>Make instructions more specific. &quot;Use 2-space indentation&quot; works better than &quot;format code nicely.&quot;</li><li>Look for conflicting instructions across CLAUDE.md files. If two files give different guidance for the same behavior, Claude may pick one arbitrarily.</li></ul><p>For instructions you want at the system prompt level, use <a href="/s/webclips/en/cli-reference.html#system-prompt-flags"><code>--append-system-prompt</code></a>. This must be passed every invocation, so it&#39;s better suited to scripts and automation than interactive use.</p>`,30)),s(r,null,{default:a(()=>[...e[6]||(e[6]=[t(" Use the [`InstructionsLoaded` hook](/en/hooks#instructionsloaded) to log exactly which instruction files are loaded, when they load, and why. This is useful for debugging path-specific rules or lazy-loaded files in subdirectories. ",-1)])]),_:1}),e[13]||(e[13]=i('<h3 id="i-don-t-know-what-auto-memory-saved" tabindex="-1">I don&#39;t know what auto memory saved <a class="header-anchor" href="#i-don-t-know-what-auto-memory-saved" aria-label="Permalink to &quot;I don&#39;t know what auto memory saved&quot;">​</a></h3><p>Run <code>/memory</code> and select the auto memory folder to browse what Claude has saved. Everything is plain markdown you can read, edit, or delete.</p><h3 id="my-claude-md-is-too-large" tabindex="-1">My CLAUDE.md is too large <a class="header-anchor" href="#my-claude-md-is-too-large" aria-label="Permalink to &quot;My CLAUDE.md is too large&quot;">​</a></h3><p>Files over 200 lines consume more context and may reduce adherence. Move detailed content into separate files referenced with <code>@path</code> imports (see <a href="#import-additional-files">Import additional files</a>), or split your instructions across <code>.claude/rules/</code> files.</p><h3 id="instructions-seem-lost-after-compact" tabindex="-1">Instructions seem lost after <code>/compact</code> <a class="header-anchor" href="#instructions-seem-lost-after-compact" aria-label="Permalink to &quot;Instructions seem lost after `/compact`&quot;">​</a></h3><p>CLAUDE.md fully survives compaction. After <code>/compact</code>, Claude re-reads your CLAUDE.md from disk and re-injects it fresh into the session. If an instruction disappeared after compaction, it was given only in conversation, not written to CLAUDE.md. Add it to CLAUDE.md to make it persist across sessions.</p><p>See <a href="#write-effective-instructions">Write effective instructions</a> for guidance on size, structure, and specificity.</p><h2 id="related-resources" tabindex="-1">Related resources <a class="header-anchor" href="#related-resources" aria-label="Permalink to &quot;Related resources&quot;">​</a></h2><ul><li><a href="/s/webclips/en/skills.html">Skills</a>: package repeatable workflows that load on demand</li><li><a href="/s/webclips/en/settings.html">Settings</a>: configure Claude Code behavior with settings files</li><li><a href="/s/webclips/en/sessions.html">Manage sessions</a>: manage context, resume conversations, and run parallel sessions</li><li><a href="/s/webclips/en/sub-agents.html#enable-persistent-memory">Subagent memory</a>: let subagents maintain their own auto memory</li></ul>',9))])}const A=h(g,[["render",f]]);export{v as __pageData,A as default};
